/**
 * @param {number[]} nums
 * @param {number} k
 * @return {number}
 */
function solve(nums, k) {
    const n = nums.length;
    if (n === 0) {
        return 0;
    }

    // dp_up[i]: maximum score of a valid alternating subsequence ending at index i,
    // where nums[i] is greater than the previous element (i.e., ... < nums[i])
    // dp_down[i]: maximum score of a valid alternating subsequence ending at index i,
    // where nums[i] is smaller than the previous element (i.e., ... > nums[i])

    // Since length 1 subsequences are always valid and are both increasing and decreasing
    // relative to a non-existent previous element, we initialize them to nums[i].
    const dp_up = new Array(n).fill(0);
    const dp_down = new Array(n).fill(0);

    let maxScore = 0;

    for (let i = 0; i < n; i++) {
        // Base case: A subsequence of length 1 always exists.
        dp_up[i] = nums[i];
        dp_down[i] = nums[i];

        for (let j = 0; j < i; j++) {
            // Check distance condition
            if (i - j >= k) {
                // Case 1: We are forming ... < nums[j] > nums[i] (dp_down[i])
                // This means the previous state ending at j must have been an 'up' sequence: ... < nums[j]
                if (nums[i] < nums[j]) {
                    // New score = max score ending at j (as an 'up' sequence) + nums[i]
                    dp_down[i] = Math.max(dp_down[i], dp_up[j] + nums[i]);
                }

                // Case 2: We are forming ... > nums[j] < nums[i] (dp_up[i])
                // This means the previous state ending at j must have been a 'down' sequence: ... > nums[j]
                if (nums[i] > nums[j]) {
                    // New score = max score ending at j (as a 'down' sequence) + nums[i]
                    dp_up[i] = Math.max(dp_up[i], dp_down[j] + nums[i]);
                }
            }
        }

        // Update overall maximum score
        maxScore = Math.max(maxScore, dp_up[i], dp_down[i]);
    }

    return maxScore;
}

